import React, { useState } from 'react';
import './App.css';

function App() {
  const [selectedFile, setSelectedFile] = useState(null);
  const [imagePreview, setImagePreview] = useState(null);
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const handleFileSelect = (event) => {
    const file = event.target.files[0];
    setSelectedFile(file);
    setResults(null);
    setError(null);

    // Create image preview
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => setImagePreview(e.target.result);
      reader.readAsDataURL(file);
    } else {
      setImagePreview(null);
    }
  };

  const handleAnalyze = async () => {
    if (!selectedFile) return;

    setLoading(true);
    setError(null);

    const formData = new FormData();
    formData.append('file', selectedFile);

    try {
      const response = await fetch('http://localhost:8000/analyze', {
        method: 'POST',
        body: formData,
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const data = await response.json();
      setResults(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const getClinicalIcon = (level) => {
    switch(level) {
      case 'HIGH': return '🔴';
      case 'MEDIUM': return '🟡';
      case 'LOW': return '🟢';
      default: return '⚪';
    }
  };

  const renderFindingRow = (pathology) => {
    const prob = pathology.probability;
    const isHigh = pathology.confidence_level === 'HIGH';
    const isMedium = pathology.confidence_level === 'MEDIUM';
    const isLow = pathology.confidence_level === 'LOW';

    let badge = null;
    if (isHigh) badge = <span className="positive-badge">✅ POSITIVE</span>;
    else if (isMedium) badge = <span className="consider-badge">⚠️ CONSIDER</span>;
    else if (isLow) badge = <span className="monitor-badge">ℹ️ MONITOR</span>;

    const confClass = isHigh ? 'color-high' : isMedium ? 'color-medium' : isLow ? 'color-low' : '';

    return (
      <div className="finding-row" key={pathology.pathology}>
        <div className="finding-name">
          {pathology.pathology}
          {badge}
        </div>
        <div className="finding-prob-col">
          <div className="finding-prob-label">Probability</div>
          <div className="finding-prob">{(prob * 100).toFixed(1)}%</div>
        </div>
        <div className={`finding-conf ${confClass}`}>
          {getClinicalIcon(pathology.confidence_level)} {pathology.confidence_level}
        </div>
      </div>
    );
  };

  return (
    <div className="App">
      <header className="App-header">
        <h1>🩺 Chest X-ray Analysis with Clinical Interpretation</h1>
        <p><strong>Enhanced DenseNet121</strong> chest X-ray pathology detection with:</p>
        <div className="header-features">
          <span className="feature-item">🔍 Clinical confidence levels (High/Medium/Low)</span>
          <span className="feature-item">🔥 Grad-CAM++ attention visualization</span>
          <span className="feature-item">📊 Optimized disease-specific thresholds</span>
          <span className="feature-item">🤖 LLM AI Explainability</span>
        </div>
      </header>

      <main className="App-main">
        <h2 className="section-header">📤 Upload Chest X-ray Image</h2>
        <div className="upload-section">
          <div className="file-input-wrapper">
            <input
              type="file"
              accept="image/png, image/jpeg, image/tiff"
              onChange={handleFileSelect}
              id="file-input"
              style={{ display: 'none' }}
            />
            <label htmlFor="file-input" className="file-label">
              <span>☁️ Drag and drop file here or click to browse</span>
              <span style={{fontSize: '0.8rem', color: '#666'}}>Limit 200MB per file • PNG, JPG, JPEG, TIFF</span>
              {selectedFile && <span style={{marginTop: '10px', color: '#fff'}}>📄 {selectedFile.name}</span>}
            </label>
          </div>

          <button
            onClick={handleAnalyze}
            disabled={!selectedFile || loading}
            className="analyze-button"
          >
            {loading ? '🔬 Analyzing...' : '🚀 Run Pathology Analysis'}
          </button>
        </div>

        {error && (
          <div className="error-message">
            ❌ Error: {error}
          </div>
        )}

        {(imagePreview || results) && (
          <div className="image-panel">
            {imagePreview && (
              <div className="image-box">
                <div className="image-box-title">📸 Uploaded X-ray</div>
                <img src={imagePreview} alt="Uploaded X-ray" />
              </div>
            )}

            {results && results.heatmap_b64 && (
              <div className="image-box">
                <div className="image-box-title">🔥 Grad-CAM++: AI Attention Map</div>
                <img src={results.heatmap_b64} alt="Grad-CAM Heatmap" />
              </div>
            )}
          </div>
        )}

        {results && (
          <div className="results-section">
            <h2 className="section-header">📋 Clinical Assessment</h2>

            {results.valid_for_analysis ? (
              <>
                {/* Clinical Assessment Banner */}
                <div className={`clinical-assessment assessment-${results.assessment_level.toLowerCase()}`}>
                  {results.assessment_level === 'NORMAL' ? '✅' : '⚠️'} {results.clinical_summary}
                </div>

                {/* AI Explanation Banner */}
                {results.ai_explanation && (
                  <div className="ai-explanation-box">
                    <h3>🤖 AI-Powered Clinical Explanation</h3>
                    <div className="ai-content">
                      {results.ai_explanation.split('\n').map((paragraph, index) => (
                        <p key={index}>{paragraph}</p>
                      ))}
                    </div>
                  </div>
                )}

                {/* Categorized Findings */}
                {(() => {
                  const high = results.pathologies.filter(p => p.confidence_level === 'HIGH');
                  const medium = results.pathologies.filter(p => p.confidence_level === 'MEDIUM');

                  return (
                    <div style={{marginTop: '30px'}}>
                      {high.length > 0 && (
                        <div className="findings-group">
                          <h3>🔴 High Confidence Findings</h3>
                          <div className="findings-group-subtitle">Probability ≥ 65% - Highly likely present</div>
                          {high.map(renderFindingRow)}
                        </div>
                      )}

                      {medium.length > 0 && (
                        <div className="findings-group">
                          <h3>🟡 Medium Confidence Findings</h3>
                          <div className="findings-group-subtitle">Probability 40-65% - Possibly present</div>
                          {medium.map(renderFindingRow)}
                        </div>
                      )}
                    </div>
                  );
                })()}

                {/* Top Predictions Bar Chart */}
                <div className="top-predictions">
                  <h3 style={{marginTop: 0, marginBottom: '20px', display: 'flex', alignItems: 'center', gap: '8px'}}>📊 Top Predictions</h3>
                  {results.pathologies
                    .sort((a, b) => b.probability - a.probability)
                    .slice(0, 5)
                    .map((pathology, index) => (
                      <div className="prediction-bar-container" key={index}>
                        <div className="pred-name">#{index + 1}. {pathology.pathology}</div>
                        <div className="pred-bar-wrapper">
                          <div 
                            className="pred-bar-fill" 
                            style={{width: `${pathology.probability * 100}%`}}
                          ></div>
                        </div>
                        <div className="pred-value">{(pathology.probability * 100).toFixed(1)}%</div>
                      </div>
                  ))}
                </div>

                <div className="model-footer">
                  <div className="model-metric">
                    <span className="model-metric-label">Model</span>
                    <span className="model-metric-value">m-30012020-104001.pth.tar</span>
                  </div>
                  <div className="model-metric">
                    <span className="model-metric-label">Device</span>
                    <span className="model-metric-value">CUDA / CPU</span>
                  </div>
                  <div className="model-metric">
                    <span className="model-metric-label">Architecture</span>
                    <span className="model-metric-value">DenseNet-121</span>
                  </div>
                </div>
              </>
            ) : (
              <div className="invalid-message">
                {results.clinical_summary || "Image validation failed. Please upload a valid chest X-ray."}
              </div>
            )}
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
